			pooledModel.add(vf.createIRI("urn:subject"), vf.createIRI("urn:predicate"), vf.createLiteral("value"),
					vf.createIRI("urn:context"));
			pooledModel.setNamespace("ex", "urn:ns:");

			recycleDynamicModel(pooledModel);
